const express = require('express');
const bodyParser = require('body-parser');
const redis = require('redis');
const twilio = require('twilio');
const app = express();

app.use(bodyParser.json());

const redisClient = redis.createClient();
const twilioClient = twilio('TWILIO_ACCOUNT_SID', 'TWILIO_AUTH_TOKEN');

const users = {}; // Store user data in memory for simplicity

app.post('/send-code', (req, res) => {
    const { phoneNumber, userId } = req.body;
    const code = Math.floor(100000 + Math.random() * 900000).toString();
    
    redisClient.setex(`mfa:${userId}`, 600, code); // Store code with 10 min expiration
    redisClient.setex(`attempts:${userId}`, 600, 0); // Initialize attempts

    twilioClient.messages.create({
        body: `Your verification code is ${code}`,
        from: 'YOUR_TWILIO_PHONE_NUMBER',
        to: phoneNumber
    }).then(() => {
        res.status(200).send('Code sent');
    }).catch(err => {
        res.status(500).send('Error sending code');
    });
});

app.post('/verify-code', (req, res) => {
    const { userId, code } = req.body;

    redisClient.get(`attempts:${userId}`, (err, attempts) => {
        if (err) return res.status(500).send('Error checking attempts');
        
        attempts = parseInt(attempts) || 0;

        if (attempts >= 10) {
            return res.status(403).send('Too many attempts, please try again later');
        }

        redisClient.get(`mfa:${userId}`, (err, storedCode) => {
            if (err) return res.status(500).send('Error verifying code');

            if (code === storedCode) {
                redisClient.del(`mfa:${userId}`);
                redisClient.del(`attempts:${userId}`);
                return res.status(200).send('Access granted');
            } else {
                redisClient.incr(`attempts:${userId}`);
                return res.status(401).send('Invalid code');
            }
        });
    });
});

app.listen(3000, () => {
    console.log('Server running on port 3000');
});